// AINE: audit VMs that do not have the Log Analytics agent extension
{
  "mode": "All",
  "displayName": "Audit VMs without Log Analytics agent",
  "parameters": {
    "logAnalyticsWorkspaceId": {
      "type": "String",
      "metadata": { "displayName": "Log Analytics Workspace ID" }
    }
  },
  "policyRule": {
    "if": {
      "anyOf": [
        { "field": "type", "equals": "Microsoft.Compute/virtualMachines" }
      ]
    },
    "then": {
      "effect": "auditIfNotExists",
      "details": {
        "type": "Microsoft.Compute/virtualMachines/extensions",
        "existenceCondition": {
          "allOf": [
            { "field": "Microsoft.Compute/virtualMachines/extensions/publisher",
              "equals": "Microsoft.EnterpriseCloud.Monitoring" },
            { "field": "Microsoft.Compute/virtualMachines/extensions/type",
              "in": ["MicrosoftMonitoringAgent", "OmsAgentForLinux"] },
            { "field": "Microsoft.Compute/virtualMachines/extensions/provisioningState",
              "equals": "Succeeded" },
            { "field": "Microsoft.Compute/virtualMachines/extensions/settings.workspaceId",
              "equals": "[parameters('logAnalyticsWorkspaceId')]" }
          ]
        }
      }
    }
  }
}

// existenceScope controls where the policy engine searches for the companion

// Default: ResourceGroup — companion must be in the same resource group
// as the triggering resource
"details": {
  "type": "Microsoft.Insights/diagnosticSettings",
  "existenceScope": "ResourceGroup",
  "existenceCondition": {
    "field": "Microsoft.Insights/diagnosticSettings/workspaceId",
    "equals": "[parameters('logAnalyticsWorkspaceId')]"
  }
}

// Subscription — companion can be anywhere in the subscription
// Useful for singleton resources like a security contact or Log Analytics workspace
"details": {
  "type": "microsoft.security/securitycontacts",
  "existenceScope": "Subscription",
  "existenceCondition": {
    "field": "Microsoft.Security/securityContacts/email",
    "notEquals": ""
  }
}

// Common mistake: no existenceCondition
// ANY diagnostic setting counts as compliant — even if pointing to a decommissioned workspace
"details": {
  "type": "Microsoft.Insights/diagnosticSettings"
  // missing existenceCondition — too permissive
}

{
  "mode": "All",
  "displayName": "Audit Key Vaults without diagnostic settings to Log Analytics",
  "parameters": {
    "logAnalyticsWorkspaceId": {
      "type": "String",
      "metadata": {
        "displayName": "Log Analytics Workspace ID",
        "description": "Resource ID of the target Log Analytics workspace"
      }
    },
    "effect": {
      "type": "String",
      "defaultValue": "AuditIfNotExists",
      "allowedValues": ["AuditIfNotExists", "Disabled"],
      "metadata": { "displayName": "Effect" }
    }
  },
  "policyRule": {
    "if": {
      "field": "type",
      "equals": "Microsoft.KeyVault/vaults"
    },
    "then": {
      "effect": "[parameters('effect')]",
      "details": {
        "type": "Microsoft.Insights/diagnosticSettings",
        "existenceCondition": {
          "allOf": [
            {
              "field": "Microsoft.Insights/diagnosticSettings/workspaceId",
              "equals": "[parameters('logAnalyticsWorkspaceId')]"
            },
            {
              "count": {
                "field": "Microsoft.Insights/diagnosticSettings/logs[*]",
                "where": {
                  "allOf": [
                    { "field": "Microsoft.Insights/diagnosticSettings/logs[*].category", "equals": "AuditEvent" },
                    { "field": "Microsoft.Insights/diagnosticSettings/logs[*].enabled", "equals": "true" }
                  ]
                }
              },
              "greater": 0
            }
          ]
        }
      }
    }
  }
}

resource "azurerm_policy_definition" "kv_aine" {
  name         = "audit-kv-diagnostic-settings"
  policy_type  = "Custom"
  mode         = "All"
  display_name = "Audit Key Vaults without diagnostic settings"

  parameters = jsonencode({
    logAnalyticsWorkspaceId = {
      type = "String"
      metadata = {
        displayName = "Log Analytics Workspace ID"
      }
    }
  })

  policy_rule = file("${path.module}/policies/kv-aine.json")
}

# AINE assignments need no managed identity — no azurerm_role_assignment required
resource "azurerm_management_group_policy_assignment" "kv_aine" {
  name                 = "audit-kv-diag"
  management_group_id  = var.management_group_id
  policy_definition_id = azurerm_policy_definition.kv_aine.id

  parameters = jsonencode({
    logAnalyticsWorkspaceId = {
      value = var.log_analytics_workspace_id
    }
  })

  # No identity block — AINE does not deploy resources
}

# If you later want DINE to auto-remediate, replace the above with a DINE definition
# and add an identity block + azurerm_role_assignment for the managed identity.

// Initiative parameter definition
{
  "auditKvDiagEffect": {
    "type": "String",
    "defaultValue": "AuditIfNotExists",
    "allowedValues": ["AuditIfNotExists", "Disabled"],
    "metadata": { "displayName": "KV Diagnostic Settings: Effect" }
  },
  "logAnalyticsWorkspaceId": {
    "type": "String",
    "metadata": { "displayName": "Log Analytics Workspace ID" }
  }
}

// Policy reference inside the initiative
{
  "policyDefinitionId": "/providers/Microsoft.Management/managementGroups/mg-corp/providers/Microsoft.Authorization/policyDefinitions/audit-kv-diag-settings",
  "parameters": {
    "effect": { "value": "[parameters('auditKvDiagEffect')]" },
    "logAnalyticsWorkspaceId": { "value": "[parameters('logAnalyticsWorkspaceId')]" }
  }
}

